struct PIIRedactor {
    
    /// Redacts an email address: "john.doe@example.com" -> "j*****e@e****e.com"
    static func redactEmail(_ email: String?) -> String {
        guard let email = email, !email.isEmpty else { return "[no-email]" }
        
        let components = email.split(separator: "@")
        guard components.count == 2 else { return "[invalid-email]" }
        
        let local = String(components[0])
        let domain = String(components[1])
        
        let redactedLocal = redactString(local, showFirst: 1, showLast: 1)
        let domainParts = domain.split(separator: ".")
        let redactedDomain = domainParts.map { part in
            redactString(String(part), showFirst: 1, showLast: 1)
        }.joined(separator: ".")
        
        return "\(redactedLocal)@\(redactedDomain)"
    }
    
    /// Redacts a user ID, showing only last 4 characters: "usr_abc123xyz" -> "***xyz"
    static func redactUserID(_ userID: String?) -> String {
        guard let userID = userID, !userID.isEmpty else { return "[no-id]" }
        if userID.count <= 4 { return "***" }
        let lastFour = String(userID.suffix(4))
        return "***\(lastFour)"
    }
    
    /// Completely redacts a token, showing only its length
    static func redactToken(_ token: String?) -> String {
        guard let token = token, !token.isEmpty else { return "[no-token]" }
        return "[token:\(token.count)chars]"
    }
    
    /// Redacts a phone number: "+1234567890" -> "+1***7890"
    static func redactPhone(_ phone: String?) -> String {
        guard let phone = phone, !phone.isEmpty else { return "[no-phone]" }
        if phone.count <= 4 { return "****" }
        let prefix = String(phone.prefix(2))
        let suffix = String(phone.suffix(4))
        return "\(prefix)***\(suffix)"
    }
    
    /// Redacts a generic string showing first N and last N characters
    static func redactString(_ string: String, showFirst: Int = 1, showLast: Int = 1) -> String {
        guard string.count > showFirst + showLast else {
            return String(repeating: "*", count: string.count)
        }
        let first = String(string.prefix(showFirst))
        let last = String(string.suffix(showLast))
        let middleCount = string.count - showFirst - showLast
        return "\(first)\(String(repeating: "*", count: middleCount))\(last)"
    }
    
    /// Redacts sensitive keys from a dictionary (for API payloads)
    static func redactDictionary(_ dict: [String: Any]?, sensitiveKeys: Set<String>? = nil) -> [String: String] {
        guard let dict = dict else { return [:] }
        
        let defaultSensitiveKeys: Set<String> = [
            "password", "pass", "pwd", "secret",
            "token", "access_token", "refresh_token", "id_token",
            "authorization", "auth", "api_key", "apikey", "api-key",
            "credit_card", "card_number", "cvv", "ssn",
            "social_security", "bank_account",
            "email", "phone", "address", "dob", "date_of_birth",
            "first_name", "last_name", "full_name", "name"
        ]
        
        let keysToRedact = sensitiveKeys ?? defaultSensitiveKeys
        
        var redacted: [String: String] = [:]
        for (key, value) in dict {
            let lowercaseKey = key.lowercased()
            if keysToRedact.contains(lowercaseKey) {
                redacted[key] = "[REDACTED]"
            } else if let nestedDict = value as? [String: Any] {
                redacted[key] = "\(redactDictionary(nestedDict, sensitiveKeys: sensitiveKeys))"
            } else if let array = value as? [Any] {
                redacted[key] = "[\(array.count) items]"
            } else {
                redacted[key] = "\(value)"
            }
        }
        return redacted
    }
    
    /// Redacts URL query parameters that may contain sensitive data
    static func redactURL(_ url: URL?) -> String {
        guard let url = url else { return "[no-url]" }
        
        let sensitiveParams: Set<String> = ["token", "key", "api_key", "secret", "password", "auth", "session"]
        
        guard var components = URLComponents(url: url, resolvingAgainstBaseURL: false) else {
            return url.path
        }
        
        if let queryItems = components.queryItems {
            components.queryItems = queryItems.map { item in
                if sensitiveParams.contains(item.name.lowercased()) {
                    return URLQueryItem(name: item.name, value: "[REDACTED]")
                }
                return item
            }
        }
        
        return components.string ?? url.path
    }
