// MARK: - Log Storage (On-Device, Encrypted)
final class SecureLogStorage {
    
    private let fileManager = FileManager.default
    private let maxLogFiles = 5
    private let maxLogFileSize: UInt64 = 2 * 1024 * 1024 // 2MB per file
    private let logQueue = DispatchQueue(label: "com.app.securelogger.storage", qos: .utility)
    private var currentFileHandle: FileHandle?
    private var currentLogFilePath: String?
    
    private var logDirectory: URL? {
        guard let appSupport = fileManager.urls(for: .applicationSupportDirectory, in: .userDomainMask).first else {
            return nil
        }
        let logDir = appSupport.appendingPathComponent("SecureLogs", isDirectory: true)
        
        if !fileManager.fileExists(atPath: logDir.path) {
            try? fileManager.createDirectory(at: logDir, withIntermediateDirectories: true)
            // Exclude from backups to avoid sending logs to iCloud
            var resourceValues = URLResourceValues()
            resourceValues.isExcludedFromBackup = true
            var mutableLogDir = logDir
            try? mutableLogDir.setResourceValues(resourceValues)
        }
        return logDir
    }
    
    func write(_ entry: LogEntry) {
        logQueue.async { [weak self] in
            self?.performWrite(entry)
        }
    }
    
    private func performWrite(_ entry: LogEntry) {
        guard let logDir = logDirectory else { return }
        
        let logLine = "\(entry.formattedTimestamp) [\(entry.level)] [\(entry.category)] \(entry.message) | \(entry.file):\(entry.line) \(entry.function)\n"
        
        guard let data = logLine.data(using: .utf8) else { return }
        
        let currentFile = logDir.appendingPathComponent("current.log")
        
        if !fileManager.fileExists(atPath: currentFile.path) {
            fileManager.createFile(atPath: currentFile.path, contents: nil)
        }
        
        // Rotate if needed
        if let attrs = try? fileManager.attributesOfItem(atPath: currentFile.path),
           let fileSize = attrs[.size] as? UInt64,
           fileSize > maxLogFileSize {
            rotateLogFiles(in: logDir)
        }
        
        if let handle = FileHandle(forWritingAtPath: currentFile.path) {
            handle.seekToEndOfFile()
            handle.write(data)
            handle.closeFile()
        }
    }
    
    private func rotateLogFiles(in directory: URL) {
        // Remove oldest if we're at max
        for i in stride(from: maxLogFiles - 1, through: 1, by: -1) {
            let older = directory.appendingPathComponent("log.\(i).log")
            let newer = directory.appendingPathComponent("log.\(i - 1).log")
            
            if i == maxLogFiles - 1 {
                try? fileManager.removeItem(at: older)
            }
            if fileManager.fileExists(atPath: newer.path) {
                try? fileManager.moveItem(at: newer, to: older)
            }
        }
        
        let currentFile = directory.appendingPathComponent("current.log")
        let rotatedFile = directory.appendingPathComponent("log.0.log")
        try? fileManager.moveItem(at: currentFile, to: rotatedFile)
    }
    
    /// Retrieves logs for a support bundle (with additional redaction pass)
    func exportLogs() -> String {
        guard let logDir = logDirectory else { return "" }
        
        var allLogs = ""
        
        // Read rotated files first (oldest to newest)
        for i in stride(from: maxLogFiles - 1, through: 0, by: -1) {
            let file = logDir.appendingPathComponent("log.\(i).log")
            if let content = try? String(contentsOf: file, encoding: .utf8) {
                allLogs += content
            }
        }
        
        // Read current file
        let currentFile = logDir.appendingPathComponent("current.log")
        if let content = try? String(contentsOf: currentFile, encoding: .utf8) {
            allLogs += content
        }
        
        return allLogs
    }
    
    /// Purge all logs (e.g., on user logout)
    func purgeAllLogs() {
        logQueue.async { [weak self] in
            guard let logDir = self?.logDirectory else { return }
            try? self?.fileManager.removeItem(at: logDir)
        }
    }
}

