// MARK: - Network Request Context (Safe for Logging)
struct SafeNetworkRequestContext {
    let method: String
    let url: String // Already redacted
    let statusCode: Int?
    let duration: TimeInterval?
    let requestBodyKeys: [String]? // Only key names, not values
    let responseBodyKeys: [String]? // Only key names, not values
    let errorDescription: String?
    let requestID: String?
    
    var summary: String {
        var parts: [String] = ["\(method) \(url)"]
        if let status = statusCode {
            parts.append("status=\(status)")
        }
        if let duration = duration {
            parts.append("duration=\(String(format: "%.2f", duration))s")
        }
        if let keys = requestBodyKeys {
            parts.append("reqKeys=[\(keys.joined(separator: ","))]")
        }
        if let keys = responseBodyKeys {
            parts.append("resKeys=[\(keys.joined(separator: ","))]")
        }
        if let error = errorDescription {
            parts.append("error=\(error)")
        }
        if let reqID = requestID {
            parts.append("reqID=\(reqID)")
        }
        return parts.joined(separator: " | ")
    }
}

