// MARK: - URLSession Integration Helper

final class NetworkLogger {
    
    static let shared = NetworkLogger()
    private let logger = SecureLogger.shared
    
    private init() {}
    
    /// Call before sending a request
    func logRequest(_ request: URLRequest) {
        let method = request.httpMethod ?? "UNKNOWN"
        let bodyKeys: [String]? = extractTopLevelKeys(from: request.httpBody)
        let requestID = request.value(forHTTPHeaderField: "X-Request-ID")
        
        logger.logAPIRequest(method: method, url: request.url, bodyKeys: bodyKeys, requestID: requestID)
    }
    
    /// Call after receiving a response
    func logResponse(_ response: URLResponse?, data: Data?, error: Error?, duration: TimeInterval, requestURL: URL?, method: String, requestID: String? = nil) {
        
        if let error = error {
            logger.logAPIError(method: method, url: requestURL, error: error, requestID: requestID)
            return
        }
        
        let httpResponse = response as? HTTPURLResponse
        let responseKeys = extractTopLevelKeys(from: data)
        
        let context = SafeNetworkRequestContext(
            method: method,
            url: PIIRedactor.redactURL(requestURL),
            statusCode: httpResponse?.statusCode,
            duration: duration,
            requestBodyKeys: nil,
            responseBodyKeys: responseKeys,
            errorDescription: nil,
            requestID: requestID
        )
        
        logger.logAPIResponse(context: context)
    }
    
    /// Extracts only top-level key names from JSON data (never values)
    private func extractTopLevelKeys(from data: Data?) -> [String]? {
        guard let data = data,
              let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any] else {
            return nil
        }
        return Array(json.keys).sorted()
    }
}

// MARK: - Analytics Tracker (Non-PII Event Tracking)

final class AnalyticsTracker {
    
    static let shared = AnalyticsTracker()
    private let logger = SecureLogger.shared
    private var eventBuffer: [AnalyticsEvent] = []
    private let bufferQueue = DispatchQueue(label: "com.app.analytics.buffer", qos: .utility)
    private let maxBufferSize = 100
    
    private init() {}
    
    func track(_ eventName: String, category: LogCategory = .userAction, properties: [String: String] = [:]) {
        let event = AnalyticsEvent(name: eventName, category: category, properties: properties)
        
        logger.log(.info, category: category,
                   message: "Event: \(eventName) props=\(properties)")
        
        bufferQueue.async { [weak self] in
            guard let self = self else { return }
            self.eventBuffer.append(event)
            if self.eventBuffer.count >= self.maxBufferSize {
                self.flush()
            }
        }
    }
    
    func trackScreenView(_ screenName: String) {
        track("screen_view", category: .navigation, properties: ["screen": screenName])
    }
    
    func trackButtonTap(_ buttonName: String, screen: String) {
        track("button_tap", category: .userAction, properties: ["button": buttonName, "screen": screen])
    }
    
    func trackError(_ errorType: String, code: String? = nil) {
        var props: [String: String] = ["type": errorType]
        if let code = code { props["code"] = code }
        track("error_occurred", category: .error, properties: props)
    }
    
    func flush() {
        bufferQueue.async { [weak self] in
            guard let self = self, !self.eventBuffer.isEmpty else { return }
            let events = self.eventBuffer
            self.eventBuffer.removeAll()
            
            // Here you would send to your analytics backend
            // For now, just log the flush
            self.logger.debug("Analytics flush: \(events.count) events", category: .lifecycle)
        }
    }
}

